102:         await ipcRenderer.invoke('save-file', selectedReport.path, newContent);
103:         setIsSaving(false);
104:       }
105:     }, 1000);
106:   };
107: 
108:   const openInVSCode = (path: string, e?: React.MouseEvent) => {
109:     if (e) e.stopPropagation();
110:     if (typeof window !== "undefined" && (window as any).require) {
111:       const { ipcRenderer } = (window as any).require("electron");
112:       ipcRenderer.send("launch-vscode", path);
113:     }
