116:   const handleDeleteReport = async (path: string, e: React.MouseEvent) => {
117:     e.stopPropagation();
118:     if (confirm("Are you sure you want to delete this report? This cannot be undone.")) {
119:       if (typeof window !== "undefined" && (window as any).require) {
120:         const { ipcRenderer } = (window as any).require("electron");
121:         await ipcRenderer.invoke('delete-file', path);
122:         if (selectedReport?.path === path) {
