131:   const generateWeeklyUpdate = () => {
132:     const doneTasks = tasks.filter(t => t.status === 'Done');
133:     const inProgressTasks = tasks.filter(t => t.status === 'In Progress');
134:     const toReviewTasks = tasks.filter(t => t.status === 'In Review');
135:     
136:     const today = new Date().toLocaleDateString();
137:     
138:     let md = `# Weekly Status Report - ${today}\n\n`;
139:     md += `## Executive Summary\n\n[Add high-level summary here]\n\n`;
140:     md += `## Progress This Week\n\n`;
141:     if (doneTasks.length === 0) md += `*No tasks completed this week.*\n\n`;
142:     doneTasks.forEach(t => md += `- **${t.title}**\n`);
143:     
144:     md += `\n## Current Focus (In Progress & Review)\n\n`;
145:     if (inProgressTasks.length === 0 && toReviewTasks.length === 0) md += `*No active tasks.*\n\n`;
146:     inProgressTasks.forEach(t => md += `- ${t.title} (In Progress)\n`);
147:     toReviewTasks.forEach(t => md += `- ${t.title} (In Review)\n`);
148:     
149:     return md;
150:   };
151: 
152:   const handleCreateReport = async (result: any) => {
153:     const filename = result.title;
154:     if (typeof window !== "undefined" && (window as any).require && projectPath) {
155:       const { ipcRenderer } = (window as any).require("electron");
156:       const pathModule = (window as any).require("path");
157:       
158:       if (selectedTemplate === 'Weekly Update (Markdown Auto-Generated)') {
159:         const safeName = filename.endsWith('.md') ? filename : `${filename}.md`;
160:         const filePath = pathModule.join(projectPath, safeName);
161:         await ipcRenderer.invoke('save-file', filePath, generateWeeklyUpdate());
162:       } else if (selectedTemplate === 'Blank Markdown') {
163:         const safeName = filename.endsWith('.md') ? filename : `${filename}.md`;
164:         const filePath = pathModule.join(projectPath, safeName);
165:         await ipcRenderer.invoke('save-file', filePath, `# ${filename}\n\nStart writing your report here...`);
166:       } else {
167:         await ipcRenderer.invoke('create-tex-file', projectPath, filename, selectedTemplate);
168:       }
169:       loadData();
170:     }
171:   };
