182:     if (!textarea) return;
183:     const start = textarea.selectionStart;
184:     const end = textarea.selectionEnd;
185:     const text = reportContent;
186:     let newText = text;
187:     let newCursorPos = start;
188: 
189:     if (format === 'bold') {
190:       newText = text.substring(0, start) + "**" + text.substring(start, end) + "**" + text.substring(end);
191:       newCursorPos = start === end ? start + 2 : end + 4;
192:     } else if (format === 'italic') {
193:       newText = text.substring(0, start) + "*" + text.substring(start, end) + "*" + text.substring(end);
194:       newCursorPos = start === end ? start + 1 : end + 2;
195:     } else if (format === 'h1') {
196:       newText = text.substring(0, start) + "\n# " + text.substring(start, end) + text.substring(end);
197:       newCursorPos = start === end ? start + 3 : end + 3;
198:     } else if (format === 'h2') {
199:       newText = text.substring(0, start) + "\n## " + text.substring(start, end) + text.substring(end);
200:       newCursorPos = start === end ? start + 4 : end + 4;
201:     } else if (format === 'ul') {
202:       newText = text.substring(0, start) + "\n- " + text.substring(start, end) + text.substring(end);
203:       newCursorPos = start === end ? start + 3 : end + 3;
204:     } else if (format === 'code') {
205:       newText = text.substring(0, start) + "`" + text.substring(start, end) + "`" + text.substring(end);
206:       newCursorPos = start === end ? start + 1 : end + 2;
207:     } else if (format === 'link') {
208:       newText = text.substring(0, start) + "[" + text.substring(start, end) + "](url)" + text.substring(end);
209:       newCursorPos = start === end ? start + 1 : end + 7;
210:     }
211: 
212:     handleContentChange(newText);
213:     setTimeout(() => {
214:       textarea.focus();
215:       textarea.setSelectionRange(newCursorPos, newCursorPos);
216:     }, 0);
217:   };
